_shaderData.warp:
#version 300 es
precision highp float;

// VisualSynth uniforms
uniform float uTime;
uniform float uFrame;
uniform float uFps;
uniform float uRms;

// Audio uniforms
uniform float audioLow;      // bass
uniform float audioLowSmooth; // bass_att
uniform float audioMid;      // mid
uniform float audioMidSmooth; // mid_att
uniform float audioHigh;     // treb
uniform float audioHighSmooth; // treb_att

// Screen uniforms
uniform float uAspectX;
uniform float uAspectY;
uniform vec2 uAspect;
uniform vec2 uTexSize;

// Random values
uniform vec2 uRandomPreset;
uniform vec2 uRandomFrame;

// Input from vertex shader
in vec2 vUv;
in float vRadius;
in float vAngle;

// Output
out vec4 fragColor;

// Textures
uniform sampler2D sampler_main;
uniform sampler2D sampler_noise_lq;
uniform sampler2D sampler_noise_mq;
uniform sampler2D sampler_noise_hq;
uniform sampler2D sampler_blur1;
uniform sampler2D sampler_blur2;
uniform sampler2D sampler_blur3;

// Helper functions
float clamp01(float x) { return clamp(x, 0.0, 1.0); }
vec2 clamp01(vec2 x) { return clamp(x, vec2(0.0), vec2(1.0)); }
vec3 clamp01(vec3 x) { return clamp(x, vec3(0.0), vec3(1.0)); }
vec4 clamp01(vec4 x) { return clamp(x, vec4(0.0), vec4(1.0)); }

// Texture helper functions
vec4 GetPixel(vec2 uv) { return texture(sampler_main, uv); }
vec4 GetBlur1(vec2 uv) { return texture(sampler_blur1, uv); }
vec4 GetBlur2(vec2 uv) { return texture(sampler_blur2, uv); }
vec4 GetBlur3(vec2 uv) { return texture(sampler_blur3, uv); }


void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;


dz.x = lum(GetPixel(vUv+hor)-GetPixel(vUv-hor));
dz.y = lum(GetPixel(vUv+ver)-GetPixel(vUv-ver));

ret += GetPixel (vUv+dz*0.03*(vRadius>0.01))*0.8 * (1-vRadius/2);

ret *= 1-0.15*lum(GetBlur1(vUv));
ret -= 0.004;

ret += 0.0005* rand_preset.x/vRadius*audioHighSmooth*slow_roam_sin;

  fragColor = ret;
}

_shaderData.comp:
#version 300 es
precision highp float;

// VisualSynth uniforms
uniform float uTime;
uniform float uFrame;
uniform float uFps;
uniform float uRms;

// Audio uniforms
uniform float audioLow;      // bass
uniform float audioLowSmooth; // bass_att
uniform float audioMid;      // mid
uniform float audioMidSmooth; // mid_att
uniform float audioHigh;     // treb
uniform float audioHighSmooth; // treb_att

// Screen uniforms
uniform float uAspectX;
uniform float uAspectY;
uniform vec2 uAspect;
uniform vec2 uTexSize;

// Random values
uniform vec2 uRandomPreset;
uniform vec2 uRandomFrame;

// Input from vertex shader
in vec2 vUv;
in float vRadius;
in float vAngle;

// Output
out vec4 fragColor;

// Textures
uniform sampler2D sampler_main;
uniform sampler2D sampler_noise_lq;
uniform sampler2D sampler_noise_mq;
uniform sampler2D sampler_noise_hq;
uniform sampler2D sampler_blur1;
uniform sampler2D sampler_blur2;
uniform sampler2D sampler_blur3;

// Helper functions
float clamp01(float x) { return clamp(x, 0.0, 1.0); }
vec2 clamp01(vec2 x) { return clamp(x, vec2(0.0), vec2(1.0)); }
vec3 clamp01(vec3 x) { return clamp(x, vec3(0.0), vec3(1.0)); }
vec4 clamp01(vec4 x) { return clamp(x, vec4(0.0), vec4(1.0)); }

// Texture helper functions
vec4 GetPixel(vec2 uv) { return texture(sampler_main, uv); }
vec4 GetBlur1(vec2 uv) { return texture(sampler_blur1, uv); }
vec4 GetBlur2(vec2 uv) { return texture(sampler_blur2, uv); }
vec4 GetBlur3(vec2 uv) { return texture(sampler_blur3, uv); }


void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;

vUv += vec2(q17,q18);
uv0 = vUv;
uv1 = (vUv-0.5)*uAspect.xy ;
z = q8/uv1.y;
uv2 = vec2 (z*uv1.x,z+q19);
z  *= 1+0.14*q11*sin(uv2.y+q10*M_PI);
uv2 = vec2 (z*uv1.x,z+q19);

water = texture(snh, uv2) + texture(snh,uv2*2+vec2(0,q19/2))/2-0.7;
iswater = (z>0)* sat((5-15*abs(uv1.x)*z) /z);
vUv += water * 0.04 *iswater;

//NEON
uv1 = (vUv-0.5)*uAspect.xy ;
tuv0 = vec2 (.5/length(uv1), atan(uv1.x,-uv1.y)/M_PI) ;
near = sat (2-tuv0.x/5);
tuv = tuv0 + vec2(q19,0);
ftu = fract(tuv.y*tubes/2)-0.5;
nshape = clamp01(1-1/trad*pow(ftu,2));
tuv.x -= nshape*2.5*sqrt(trad)/tubes*tuv0.x;
k1 = abs(sin(tuv.x/tlen*M_PI*2));
nshape *= sat(k1*2);
istube = nshape >0;
uv5  = tuv*vec2(0.25/tlen,tubes/16.0);
col = (texture(sampler_rand00,uv5/32)+0.2);

neon = pow(nshape,0.41)*sat(8*k1)*col;
neons= 1.4*sat(k1)* clamp01(exp(-5*abs(ftu))) * col ;

float dir = (int(uv5.y*16)%tubes)/2;
nmask = fract(((q4*uv5.x*8.0 + 0*(int(uv5.y*16)%tubes)/2) *q20-q21)) < q22;
//nmask = sat(2/q22-2/tria((uv5.x*8.0*q20-q21))) ;
nmask *=  sat(tria((uv5.y*16.0+1)/q25+q27*2)*q26 -q26+1) ;
nmask = mix(nmask,0.15,q6);

noise =  texture(snl,tuv*2)- texture(snl,tuv*2+2*uTexSize.zw)*0.7;
noise += texture(sampler_rand00,tuv*vec2(0.5,2)+vec2(0,tuv.x*0.2)).g*-0.15 ;
noise *= !istube * near;

ret = GetPixel(vUv) + GetPixel(vec2 (vUv.x,1-vUv.y))*0;
ret  *= (vUv.x<1) * (vUv.x>0)* (vUv.y<1) * (vUv.y>0);
ret *= .8;
ret += near/2*istube*GetBlur1(vUv -ftu*istube);
ret += (neon*(1.5-q6/2) + 6*neons*noise.x)* near*nmask;

//Hintergrundbel.
uv2 = fract(uv1*.15*length(uv1)+0.5 +ftu*.5 *istube);
ret += (GetPixel(uv2)*0.6+0.1)*(noise*(.5+audioMidSmooth) +nshape * near);

vec3 shine = ret;
float radi=1;
float scale=1.6/anz;
for (int n=1; n <= anz; n++)
{
  shine += scale*GetBlur1((uv0-0.5)*radi+0.5) ;
  radi -= .9/anz ;
}


ret = shine * (1-0*sat(5*iswater)*0.2);

//ret = 1-exp(-ret*1.6);

  fragColor = ret;
}
